/**
 * palette.ts — 12 data-driven palettes matching the original HTML renderer.
 * Each palette has 5 HSL-range slots: [hMin,hMax,sMin,sMax,lMin,lMax]
 * Colors are generated by sampling within ranges using a seeded RNG.
 * Slot roles: 0=DOM, 1=SEC, 2=ACC, 3=BLK, 4=WHT
 */

export type RGB = [number, number, number];

function hslToRgb(h: number, s: number, l: number): RGB {
  s /= 100; l /= 100;
  const k = (n: number) => (n + h / 30) % 12;
  const a = s * Math.min(l, 1 - l);
  const f = (n: number) => l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
  return [Math.round(f(0) * 255), Math.round(f(8) * 255), Math.round(f(4) * 255)];
}

function sampleSlot(
  [hMin, hMax, sMin, sMax, lMin, lMax]: number[],
  rh: number, rs: number, rl: number,
): RGB {
  return hslToRgb(hMin + rh * (hMax - hMin), sMin + rs * (sMax - sMin), lMin + rl * (lMax - lMin));
}

/** rgba(r,g,b,alpha) helper */
export function rc([r, g, b]: RGB, a = 1): string {
  return `rgba(${r},${g},${b},${a})`;
}

/** XOR-shift seeded RNG — matches original */
function xorRng(seed: number) {
  let s = (seed >>> 0) || 1;
  return () => { s ^= s << 13; s ^= s >> 17; s ^= s << 5; return (s >>> 0) / 0xffffffff; };
}

