/** Select palette ID from operational stats */
export function selectPaletteId(
  errors: number, txns: number, posts: number, peakHour: number, glitchIndex: number,
): string {
  for (const p of PALETTES) {
    if (p.check(errors, txns, posts, peakHour, glitchIndex)) return p.id;
  }
  return 'MERIDIAN';
}

/** Generate 5 RGB colors [DOM, SEC, ACC, BLK, WHT] from palette + seed */
export function generateColors(paletteId: string, seed: number): [RGB, RGB, RGB, RGB, RGB] {
  const pal = PALETTES.find(p => p.id === paletteId) ?? PALETTES[6]; // MERIDIAN fallback
  const rng = xorRng((seed ^ 0xc0a7d1a5) >>> 0);
  const colors = pal.slots.map(slot => sampleSlot(slot, rng(), rng(), rng()));
  return colors as [RGB, RGB, RGB, RGB, RGB];
}

/** Backward-compat shim for pipeline (returns string[] palette) */
export function selectPalette(dayLog: {
  errors?: number; txns?: number; posts?: number; peakHour?: number;
  glitchIndex?: number; dayNumber?: number;
}): { id: string; label: string; colors: string[] } {
  const errors = dayLog.errors ?? 0;
  const txns = dayLog.txns ?? 0;
  const posts = dayLog.posts ?? 0;
  const peakHour = dayLog.peakHour ?? 14;
  const glitchIndex = dayLog.glitchIndex ?? 0;
  const id = selectPaletteId(errors, txns, posts, peakHour, glitchIndex);
  const pal = PALETTES.find(p => p.id === id)!;
  const seed = dayLog.dayNumber ?? 1;
  const rgbs = generateColors(id, seed);
  return {
    id,
    label: pal.label,
    colors: rgbs.map(([r,g,b]) => `rgb(${r},${g},${b})`),
  };
}

export function computeGlitchIndex(stats: { errors?: number; txns?: number; messages?: number }): number {
  return Math.min(100, Math.max(0,
    (stats.errors ?? 0) * 3 + (stats.txns ?? 0) / 10 + (stats.messages ?? 0) / 100,
  ));
}
